const iterations = $.steps.fetchDetails.response.iterations || [];
let compiled = '';
let emailCount = 0;

iterations.forEach((iter, i) => {
  if (!iter.getMsg || !iter.getMsg.response) return;
  const msg = iter.getMsg.response;
  const headers = msg.payload ? (msg.payload.headers || []) : [];
  const getHeader = (name) => { const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase()); return h ? h.value : ''; };

  const from = getHeader('From');
  const subject = getHeader('Subject');
  const date = getHeader('Date');

  let body = '';
  if (msg.payload && msg.payload.body && msg.payload.body.data) {
    try { body = Buffer.from(msg.payload.body.data, 'base64').toString('utf8'); } catch(e) { body = ''; }
  } else if (msg.payload && msg.payload.parts) {
    const textPart = msg.payload.parts.find(p => p.mimeType === 'text/plain');
    if (textPart && textPart.body && textPart.body.data) {
      try { body = Buffer.from(textPart.body.data, 'base64').toString('utf8'); } catch(e) { body = ''; }
    }
  }
  if (!body) body = msg.snippet || '';

  compiled += '--- INVOICE EMAIL ' + (i + 1) + ' ---\n';
  compiled += 'From: ' + from + '\n';
  compiled += 'Subject: ' + subject + '\n';
  compiled += 'Date: ' + date + '\n';
  compiled += 'Body:\n' + body.slice(0, 3000) + '\n\n';
  emailCount++;
});

return { compiled: compiled.slice(0, 30000), emailCount };

const d = $.steps.compileEmails.output;

let prompt = 'You are an expert invoice data extractor. Extract structured invoice data from the following emails.\n\n';
prompt += 'EMAILS (' + d.emailCount + ' invoice emails):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract: vendor name, invoice number, date, due date, total amount, currency, line items if visible\n';
prompt += '- Parse amounts carefully — remove currency symbols for the numeric value but note the currency\n';
prompt += '- If data is ambiguous or missing, use "N/A"\n';
prompt += '- Each invoice should be a separate entry\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "invoices": [\n';
prompt += '    {\n';
prompt += '      "vendor": "company name",\n';
prompt += '      "invoiceNumber": "INV-001",\n';
prompt += '      "invoiceDate": "YYYY-MM-DD",\n';
prompt += '      "dueDate": "YYYY-MM-DD",\n';
prompt += '      "totalAmount": "1234.56",\n';
prompt += '      "currency": "USD",\n';
prompt += '      "category": "software|services|supplies|other",\n';
prompt += '      "senderEmail": "email@example.com",\n';
prompt += '      "description": "brief description of what this invoice is for"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalExtracted": 0,\n';
prompt += '  "grandTotal": "sum of all amounts",\n';
prompt += '  "summary": "brief summary of all invoices"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { invoices: [], totalExtracted: 0, grandTotal: '0', summary: raw }; }

const ai = $.steps.parseAI.output;
const invoices = ai.invoices || [];

const header = ['Vendor', 'Invoice Number', 'Invoice Date', 'Due Date', 'Amount', 'Currency', 'Category', 'Sender Email', 'Description'];
const rows = invoices.map(inv => [
  inv.vendor || 'N/A',
  inv.invoiceNumber || 'N/A',
  inv.invoiceDate || 'N/A',
  inv.dueDate || 'N/A',
  inv.totalAmount || '0',
  inv.currency || 'USD',
  inv.category || 'other',
  inv.senderEmail || 'N/A',
  inv.description || ''
]);

const allRows = [header].concat(rows);
return { values: allRows, invoiceCount: invoices.length, grandTotal: ai.grandTotal || '0', summary: ai.summary || '' };

const ai = $.steps.parseAI.output;
const d = $.steps.buildSheetRows.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Invoice Data Extraction Complete', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Invoices extracted:* ' + d.invoiceCount + ' | *Grand total:* ' + d.grandTotal } });

if (d.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: d.summary.slice(0, 2900) } });
}
blocks.push({ type: 'divider' });

(ai.invoices || []).slice(0, 10).forEach((inv, i) => {
  let text = (i + 1) + '. *' + inv.vendor + '* - ' + inv.currency + ' ' + inv.totalAmount + '\n';
  text += '   Invoice: ' + inv.invoiceNumber + ' | Date: ' + inv.invoiceDate;
  if (inv.dueDate && inv.dueDate !== 'N/A') text += ' | Due: ' + inv.dueDate;
  text += '\n   _' + (inv.description || 'No description') + '_';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Gmail + Claude AI | One CLI' }] });

const fallback = 'Invoice Extraction: ' + d.invoiceCount + ' invoices, total ' + d.grandTotal;
return { blocks, fallback };
